var (
	fontMap        map[string]string
	fontOnce       sync.Once
	translateCache sync.Map
)

func loadFontMap() {
	fontOnce.Do(func() {
		fontMap = make(map[string]string)
		var items []struct {
			Code string `json:"code"`
			Text string `json:"text"`
		}
		// Unmarshal the JSON string. Errors are ignored as the string is constant.
		_ = json.Unmarshal([]byte(text_map), &items)
		for _, item := range items {
			fontMap[item.Code] = item.Text
		}
	})
}

func TranslateText(char string) string {
	if char == "" {
		return ""
	}
	if cached, ok := translateCache.Load(char); ok {
		return cached.(string)
	}
	loadFontMap()

	// Convert the first rune of the string to its hexadecimal representation
	r := []rune(char)[0]
	// Format as 0xXXXX (uppercase hex)
	code := fmt.Sprintf("0x%X", r)

	if val, ok := fontMap[code]; ok {
		translateCache.Store(char, val)
		return val
	}
	// Return the original character if no mapping is found
	translateCache.Store(char, char)
	return char
}
